        'message', 'msg', 'name', 'pathname', 'process', 'processName',
        'relativeCreated', 'stack_info', 'thread', 'threadName'
    })

    def __init__(self, component: str = 'emailservice'):
        super().__init__()
        self.component = component

    def format(self, record: logging.LogRecord) -> str:
        try:
            log_data = {
                'timestamp': self._format_timestamp(record.created),
                'severity': record.levelname,
                'message': record.getMessage(),
                'component': self.component
            }
            context = self._extract_context(record)
            if context:
                log_data.update(context)
            if record.exc_info:
                log_data['exception'] = self.formatException(record.exc_info)
            return json.dumps(log_data, default=str)
        except (TypeError, ValueError):
            return json.dumps({'error': 'Failed to format log record'}, default=str)

    def _format_timestamp(self, created: float) -> str:
        return datetime.datetime.utcfromtimestamp(created).strftime('%Y-%m-%dT%H:%M:%S.%f') + 'Z'

    def _extract_context(self, record: logging.LogRecord) -> Dict[str, Any]:
        context = {}
        for key, value in record.__dict__.items():
            if key not in self.RESERVED_ATTRS and not key.startswith('_'):
                context[key] = value
        return context


class JsonFormatter(logging.Formatter):
    def format(self, record) -> str:
        try:
            log_entry = {
                'timestamp': datetime.datetime.utcfromtimestamp(record.created).isoformat() + 'Z',
                'severity': record.levelname,
                'name': record.name,
                'message': record.getMessage()
            }
            return json.dumps(log_entry)
        except Exception:
            return json.dumps({'error': 'Failed to format log record'}, default=str)


def getJSONLogger(name: Optional[str] = None, level: int = logging.INFO) -> logging.Logger:
    logger = logging.getLogger(name or 'emailservice')
    if not logger.handlers:
        handler = logging.StreamHandler(sys.stdout)
        handler.setFormatter(CustomJsonFormatter())
        logger.addHandler(handler)
        logger.setLevel(level)
        logger.propagate = False
    return logger


def get_logger(name: str = 'emailservice') -> logging.Logger:
    logger = logging.getLogger(name)
    if not logger.handlers:
        handler = logging.StreamHandler(sys.stdout)
        handler.setFormatter(JsonFormatter())
        logger.addHandler(handler)
        logger.setLevel(logging.INFO)
        logger.propagate = False
    return logger


